INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1414', '68ebb28d', 'detecting-mobile-malware-behavior', 'Detecting Mobile Malware Behavior', '1.0.0', 'malware', 'T08 — ZURD', 'T08', 'security', 'Detects and analyzes malicious behavior in mobile applications through behavioral analysis, permission abuse detection, network traffic monitoring, and dynamic instrumentation. Use when analyzing suspicious mobile applications for data exfiltration, command-and-control communication, credential stealing, SMS interception, or other malware indicators. Activates for requests involving mobile malware analysis, app behavior monitoring, trojan detection, or suspicious app investigation.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1415', '0f433f6e', 'detecting-modbus-command-injection-attacks', 'Detecting Modbus Command Injection Attacks', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Detect command injection attacks against Modbus TCP/RTU protocol in ICS environments by monitoring for unauthorized write operations, anomalous function codes, malformed frames, and deviations from established communication baselines using ICS-aware IDS and protocol deep packet inspection.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1416', '7692eab8', 'detecting-modbus-protocol-anomalies', 'Detecting Modbus Protocol Anomalies', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill covers detecting anomalies in Modbus/TCP and Modbus RTU communications in industrial control systems. It addresses function code monitoring, register range validation, timing analysis, unauthorized client detection, and deep packet inspection for malformed Modbus frames. The skill leverages Zeek with Modbus protocol analyzers, Suricata IDS with OT rules, and custom Python-based detection using Markov chain models for normal Modbus transaction sequences.
