INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1439', '9a96c90c', 'executing-active-directory-attack-simulation', 'Executing Active Directory Attack Simulation', '1.0.0', 'pentesting', 'T08 — ZURD', 'T08', 'security', 'Executes authorized attack simulations against Active Directory environments to identify misconfigurations, weak credentials, dangerous privilege paths, and exploitable trust relationships that could lead to domain compromise. The tester uses BloodHound for attack path analysis, Mimikatz for credential extraction, and Impacket for protocol-level attacks including Kerberoasting, AS-REP Roasting, and delegation abuse. Activates for requests involving Active Directory pentest, AD attack simulation,', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1440', 'c3dba46d', 'executing-diamond-model-analysis', 'Executing Diamond Model Analysis', '1.0.0', 'threat-intelligence', 'T06 — EDNA', 'T06', 'security', 'Applies the Diamond Model of Intrusion Analysis to structure adversary activity into its four core vertices (adversary, capability, infrastructure, victim) and identifies relationships between them to pivot investigations and attribute campaigns. Use when analyzing a completed intrusion, linking disparate incidents to a common threat actor, or building structured analytic products for threat intelligence dissemination. Activates for requests involving Diamond Model, intrusion analysis, campaign ', '', '', 'Edna-SIGINT', 9, 'restricted', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1441', '50c66f3b', 'executing-phishing-simulation-campaign', 'Executing Phishing Simulation Campaign', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Executes authorized phishing simulation campaigns to assess an organization''s susceptibility to email-based social engineering attacks. The tester designs realistic phishing scenarios, builds credential harvesting infrastructure, sends targeted phishing emails, and tracks open rates, click-through rates, and credential submission rates to measure human security awareness. Activates for requests involving phishing simulation, social engineering assessment, email security testing, or security awar', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1442', '5cdde65e', 'executing-red-team-engagement-planning', 'Executing Red Team Engagement Planning', '1.0.0', 'red-team', 'T08 — ZURD', 'T08', 'security', 'Red team engagement planning is the foundational phase that defines scope, objectives, rules of engagement (ROE), threat model selection, and operational timelines before any offensive testing begins.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1443', '95cb9fa2', 'executing-red-team-exercise', 'Executing Red Team Exercise', '1.0.0', 'red-team', 'T08 — ZURD', 'T08', 'security', 'Executes comprehensive red team exercises that simulate real-world adversary operations against an organization''s people, processes, and technology. The red team operates with stealth as a primary objective, employing the full attack lifecycle from initial reconnaissance through objective completion while testing the organization''s detection and response capabilities. This differs from penetration testing by focusing on adversary emulation rather than vulnerability identification. Activates for ', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
