INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1448', '4a2c96f3', 'exploiting-broken-function-level-authorization', 'Exploiting Broken Function Level Authorization', '1.0.0', 'red-team', 'T08 — ZURD', 'T08', 'security', 'Tests APIs for Broken Function Level Authorization (BFLA) vulnerabilities where regular users can invoke administrative functions or access privileged API endpoints by directly calling them. The tester identifies admin and privileged endpoints, then attempts to access them with regular user credentials by manipulating HTTP methods, URL paths, and request parameters. Maps to OWASP API5:2023 Broken Function Level Authorization. Activates for requests involving BFLA testing, admin endpoint bypass, ', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
