INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1452', 'dba61054', 'exploiting-excessive-data-exposure-in-api', 'Exploiting Excessive Data Exposure In Api', '1.0.0', 'red-team', 'T08 — ZURD', 'T08', 'security', 'Tests APIs for excessive data exposure where endpoints return more data than the client application needs, relying on the frontend to filter sensitive fields. The tester intercepts API responses and analyzes them for leaked PII, internal identifiers, debug information, or sensitive business data that the UI does not display but the API transmits. This maps to OWASP API3:2023 Broken Object Property Level Authorization. Activates for requests involving API data leakage testing, excessive data expo', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
