INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1723', '18823091', 'performing-purple-team-exercise', 'Performing Purple Team Exercise', '1.0.0', 'threat-intelligence', 'T06 — EDNA', 'T06', 'security', 'Performs purple team exercises by coordinating red team adversary emulation with blue team detection validation using MITRE ATT&CK-mapped attack scenarios, real-time detection testing, and collaborative gap remediation. Use when SOC teams need to validate detection capabilities, improve analyst skills, and close detection gaps through structured offensive-defensive collaboration.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1724', 'f5cc34ec', 'performing-ransomware-incident-response', 'Performing Ransomware Incident Response', '1.0.0', 'forensics', 'T08 — ZURD', 'T08', 'security', 'Execute a structured ransomware incident response including containment, decryption assessment, recovery from backups, and eradication of ransomware persistence mechanisms.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
