INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1778', 'acf58bb5', 'securing-aws-iam-permissions', 'Securing Aws Iam Permissions', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill guides practitioners through hardening AWS Identity and Access Management configurations to enforce least privilege access across cloud accounts. It covers IAM policy scoping, permission boundaries, Access Analyzer integration, and credential rotation strategies to reduce the blast radius of compromised identities.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1779', 'c6539c60', 'securing-aws-lambda-execution-roles', 'Securing Aws Lambda Execution Roles', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Securing AWS Lambda execution roles by implementing least-privilege IAM policies, applying permission boundaries, restricting resource-based policies, using IAM Access Analyzer to validate permissions, and enforcing role scoping through SCPs.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1780', 'bde87358', 'securing-azure-with-microsoft-defender', 'Securing Azure With Microsoft Defender', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill instructs security practitioners on deploying Microsoft Defender for Cloud as a cloud-native application protection platform for Azure, multi-cloud, and hybrid environments. It covers enabling Defender plans for servers, containers, storage, and databases, configuring security recommendations, managing Secure Score, and integrating with the unified Defender portal for centralized threat management.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1781', '6fb83a0b', 'securing-container-registry-images', 'Securing Container Registry Images', '1.0.0', 'pentesting', 'T08 — ZURD', 'T08', 'security', 'Securing container registry images by implementing vulnerability scanning with Trivy and Grype, enforcing image signing with Cosign and Sigstore, configuring registry access controls, and building CI/CD pipelines that prevent deploying unscanned or unsigned images.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1782', 'a6f2ea84', 'securing-github-actions-workflows', 'Securing Github Actions Workflows', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill covers hardening GitHub Actions workflows against supply chain attacks, credential theft, and privilege escalation. It addresses pinning actions to SHA digests, minimizing GITHUB_TOKEN permissions, protecting secrets from exfiltration, preventing script injection in workflow expressions, and implementing required reviewers for workflow changes.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1783', '43c23282', 'securing-helm-chart-deployments', 'Securing Helm Chart Deployments', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Secure Helm chart deployments by validating chart integrity, scanning templates for misconfigurations, and enforcing security contexts in Kubernetes releases.', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1784', '945ad749', 'securing-historian-server-in-ot-environment', 'Securing Historian Server In Ot Environment', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill covers hardening and securing process historian servers (OSIsoft PI, Honeywell PHD, GE Proficy, AVEVA Historian) in OT environments. It addresses network placement across Purdue levels, access control for historian interfaces, data replication through DMZ using data diodes or PI-to-PI connectors, SQL injection prevention in historian queries, and integrity protection of process data used for safety analysis, regulatory reporting, and process optimization.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1785', 'a694a073', 'securing-kubernetes-on-cloud', 'Securing Kubernetes On Cloud', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill covers hardening managed Kubernetes clusters on EKS, AKS, and GKE by implementing Pod Security Standards, network policies, workload identity, RBAC scoping, image admission controls, and runtime security monitoring. It addresses cloud-specific security features including IRSA for EKS, Workload Identity for GKE, and Managed Identities for AKS.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1786', 'b0528fa9', 'securing-remote-access-to-ot-environment', 'Securing Remote Access To Ot Environment', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'This skill covers implementing secure remote access to OT/ICS environments for operators, engineers, and vendors while preventing unauthorized access that could compromise industrial operations. It addresses jump server architecture, multi-factor authentication, session recording, privileged access management, vendor remote access controls, and compliance with IEC 62443 and NERC CIP-005 remote access requirements.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1787', 'f8ca50ae', 'securing-serverless-functions', 'Securing Serverless Functions', '1.0.0', 'pentesting', 'T08 — ZURD', 'T08', 'security', 'This skill covers security hardening for serverless compute platforms including AWS Lambda, Azure Functions, and Google Cloud Functions. It addresses least privilege IAM roles, dependency vulnerability scanning, secrets management integration, input validation, function URL authentication, and runtime monitoring to protect against injection attacks, credential theft, and supply chain compromises.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1788', '278af0d6', 'testing-android-intents-for-vulnerabilities', 'Testing Android Intents For Vulnerabilities', '1.0.0', 'security', 'T08 — ZURD', 'T08', 'security', 'Tests Android inter-process communication (IPC) through intents for vulnerabilities including intent injection, unauthorized component access, broadcast sniffing, pending intent hijacking, and content provider data leakage. Use when assessing Android app attack surface through exported components, testing intent-based data flows, or evaluating IPC security. Activates for requests involving Android intent security, IPC testing, exported component analysis, or Drozer assessment.
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1789', 'a2f58563', 'testing-api-authentication-weaknesses', 'Testing Api Authentication Weaknesses', '1.0.0', 'red-team', 'T08 — ZURD', 'T08', 'security', 'Tests API authentication mechanisms for weaknesses including broken token validation, missing authentication on endpoints, weak password policies, credential stuffing susceptibility, token leakage in URLs or logs, and session management flaws. The tester evaluates JWT implementation, API key handling, OAuth flows, and session token entropy to identify authentication bypasses. Maps to OWASP API2:2023 Broken Authentication. Activates for requests involving API authentication testing, token validat', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1790', '2e426586', 'testing-api-for-broken-object-level-authorization', 'Testing Api For Broken Object Level Authorization', '1.0.0', 'red-team', 'T08 — ZURD', 'T08', 'security', 'Tests REST and GraphQL APIs for Broken Object Level Authorization (BOLA/IDOR) vulnerabilities where an authenticated user can access or modify resources belonging to other users by manipulating object identifiers in API requests. The tester intercepts API calls, identifies object ID parameters (numeric IDs, UUIDs, slugs), and systematically replaces them with IDs belonging to other users to determine if the server enforces per-object authorization. This is OWASP API Security Top 10 2023 risk API', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
INSERT INTO marketplace_skills (skill_id, registry_id, name, display_name, version, category, thread, thread_code, domain, description, trigger_keywords, delegation_targets, key_systems, sovereignty_score, governance_level, psi_minimum, status, author) VALUES ('ACU-SKILL-1791', 'f75a9ba5', 'testing-api-for-mass-assignment-vulnerability', 'Testing Api For Mass Assignment Vulnerability', '1.0.0', 'pentesting', 'T08 — ZURD', 'T08', 'security', 'Tests APIs for mass assignment (auto-binding) vulnerabilities where clients can modify object properties they should not have access to by including additional parameters in API requests. The tester identifies writable endpoints, adds undocumented fields to request bodies (role, isAdmin, price, balance), and checks if the server binds these to the data model without filtering. Part of OWASP API3:2023 Broken Object Property Level Authorization. Activates for requests involving mass assignment tes', '', '', 'Tenebris-ACIWS', 10, 'sovereign', 10.0, 'draft', 'cybersecurity-community');
